const formatDate = (date: Date) => format(date, 'dd/MM/yyyy');

type Office = {
  name: string;
  code: string;
  country: string;
  indent?: boolean;
};

const offices: Office[] = [
  { name: 'Barcelona', code: 'BCN', country: 'Spain' },
  { name: 'Beijing', code: 'Any', country: 'China' },
  { name: 'Budapest', code: 'BUD', country: 'Hungary' },
  { name: 'Edinburgh', code: 'EDI', country: 'United Kingdom' },
  { name: 'Glasgow', code: 'Any', country: 'United Kingdom', indent: true },
  { name: 'London', code: 'Any', country: 'United Kingdom' },
  { name: 'Miami, FL', code: 'Any', country: 'United States' },
  { name: "Shenzhen Bao'an International", code: 'SZX', country: 'China' },
  { name: 'Singapore Changi', code: 'SIN', country: 'Singapore' },
  { name: 'Sofia', code: 'SOF', country: 'Bulgaria' },
];

const getSuggestions = (value: string) => {
  const inputValue = value.trim().toLowerCase();
  const inputLength = inputValue.length;

  return inputLength === 0
    ? []
    : offices.filter(
        (office) => office.name.toLowerCase().indexOf(inputValue) !== -1,
      );
};

const getSuggestionValue = (suggestion: { name: string; code: string }) =>
  `${suggestion.name} (${suggestion.code})`;

type FieldsetContainerProps = {
  validStates: Array<boolean | null>;
  isCheckbox?: boolean;
  disabled?: boolean;
  label?: string;
  validationMessage?: string;
  description?: string;
  required?: boolean;
  className?: string | null;
  children: ReactElement<any>;
};

type FieldsetContainerState = {
  value: string;
  checked: boolean;
  validState: number;
  valueDate: Date | null;
};

class FieldsetContainer extends Component<
  FieldsetContainerProps,
  FieldsetContainerState
> {
  static defaultProps = {
    isCheckbox: false,
    disabled: false,
  };

  constructor(props: FieldsetContainerProps) {
    super(props);

    this.state = {
      value: '',
      checked: false,
      validState: 0,
      valueDate: null,
    };
  }

  onChange = (
    e: ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >,
  ) => {
    const { value } = e.target;

    this.setState((prevState) => ({
      value,
      checked:
        'checked' in e.target && typeof e.target.checked === 'boolean'
          ? e.target.checked
          : prevState.checked,
    }));
  };

  onDateSelect = (dt: Date) => {
    this.setState({
      valueDate: dt,
    });
  };

  toggleStates = () => {
    this.setState((prevState) => {
      let nextValidState = prevState.validState + 1;
      let isChecked = prevState.checked;

      if (nextValidState > this.props.validStates.length - 1) {
        nextValidState = 0;
      }

      if (this.props.isCheckbox) {
        if (prevState.checked === false && nextValidState === 1) {
          isChecked = true;
        } else {
          isChecked = false;
        }
      }

      return {
        validState: nextValidState,
        checked: isChecked,
      };
    });
  };

  render() {
    const { children, className, isCheckbox, validStates, ...rest } =
      this.props;
    const { validState, value, valueDate } = this.state;
    const valid = validStates[validState];

    const dynamicProps = isCheckbox
      ? { checked: this.state.checked }
      : { value, date: valueDate, valid };

    const dynamicFieldsetProps = isCheckbox ? { valid } : {};

    const clonedChildren = cloneElement(children, {
      onChange: this.onChange,
      onDateSelect: this.onDateSelect,
      ...dynamicProps,
    });

    const classNames = getClassName('bpk-fieldsets__fieldset', className);

    const fieldsetProps = {
      className: classNames,
      isCheckbox,
      valid,
      ...rest,
      ...dynamicFieldsetProps,
      children: clonedChildren,
    } as BpkFieldsetProps;

    return (
      <div className={getClassName('bpk-fieldsets__container')}>
        <BpkFieldset {...fieldsetProps} />
        {!this.props.disabled && (
          <div className={getClassName('bpk-fieldsets__toggle')}>
            <BpkButton onClick={this.toggleStates}>Toggle states</BpkButton>
          </div>
        )}
      </div>
    );
  }
}

class Autosuggest extends Component<
  Record<string, never>,
  { suggestions: Office[] }
> {
  constructor(props: Record<string, never>) {
    super(props);

    this.state = {
      suggestions: [],
    };
  }

  onSuggestionsFetchRequested = (value: string) => {
    this.setState({
      suggestions: getSuggestions(value),
    });
  };

  onSuggestionsClearRequested = () => {
    this.setState({
      suggestions: [],
    });
  };

  render() {
    const { suggestions } = this.state;

    const inputProps = {
      name: 'my_autosuggest',
      placeholder: 'Enter a destination name',
    };

    return (
      <FieldsetContainer
        label="Destination"
        validationMessage="Please select a destination."
        validStates={[true, false]}
        description="The final price will be adjusted based on your selection"
      >
        <BpkAutosuggest
          id="carhire-search-controls-location-pick-up"
          ariaLabels={{
            label: 'Destination',
            resultsList: 'Destination suggestions',
            clearButton: 'Clear input',
          }}
          getA11yResultsMessage={(count: number) =>
            `${count} result${count === 1 ? '' : 's'}`
          }
          suggestions={suggestions}
          onSuggestionsFetchRequested={this.onSuggestionsFetchRequested}
          onSuggestionsClearRequested={this.onSuggestionsClearRequested}
          getSuggestionValue={getSuggestionValue}
          renderSuggestion={(suggestion: Office) => (
            <BpkAutosuggestSuggestion
              value={getSuggestionValue(suggestion)}
              indent={suggestion.indent}
            />
          )}
          inputProps={inputProps}
        />
      </FieldsetContainer>
    );
  }
}

